import React, { useState } from 'react';
import QuestionForm from './components/QuestionForm';
import './styles.css';  // Importamos los estilos

function App() {
  const [submitted, setSubmitted] = useState(false);
  const [answers, setAnswers] = useState([]);

  const handleFormSubmit = (userAnswers) => {
    setAnswers(userAnswers);
    setSubmitted(true);
    // Aquí luego conectamos con la IA
  };

  return (
    <div className="container">
      <h1>Entrevista Inteligente RH</h1>
      {!submitted ? (
        <QuestionForm onSubmit={handleFormSubmit} />
      ) : (
        <div>
          <h2>Gracias por tus respuestas</h2>
          <p>Pronto recibirás una evaluación.</p>
        </div>
      )}
    </div>
  );
}

export default App;
